const cloneTierRows = (rows: TierListRow[]): TierListRow[] => rows.map((row) => ({ ...row, entries: row.entries.map((entry) => ({ ...entry })) }));

function fillPvpTierRows(seedRows: TierListRow[], fallbackRows: TierListRow[]) {
  const rows = cloneTierRows(seedRows);
  const rowsByTier = new Map(rows.map((row) => [row.tier, row]));
  const seededSourceNames = new Set(rows.flatMap((row) => row.entries.map((entry) => entry.sourceName)));

  for (const fallbackRow of fallbackRows) {
    const missingEntries = fallbackRow.entries.filter((entry) => !seededSourceNames.has(entry.sourceName));
    if (!missingEntries.length) continue;

    const row = rowsByTier.get(fallbackRow.tier);
    if (row) {
      row.entries.push(...missingEntries.map((entry) => ({ ...entry })));
      continue;
    }

    const nextRow = {
      tier: fallbackRow.tier,
      entries: missingEntries.map((entry) => ({ ...entry })),
    };
    rows.push(nextRow);
    rowsByTier.set(nextRow.tier, nextRow);
  }

  return rows;
}

export const pveTierListRows: TierListRow[] = cloneTierRows(thanosVibsTierSeed);
export const pvpTierListRows: TierListRow[] = fillPvpTierRows(pvpTierSeed, thanosVibsTierSeed);

export const tierListRowsByMode: Record<TierListMode, TierListRow[]> = {
  pve: pveTierListRows,
  pvp: pvpTierListRows,
};
